import org.apache.kafka.clients.producer.*;
import java.util.*;
import java.util.concurrent.ExecutionException;

public class KeyOrderingDemo {
    public static void main(String[] args) throws ExecutionException, InterruptedException {
        Properties props = new Properties();
        props.put("bootstrap.servers", "localhost:9092");
        props.put("key.serializer",
            "org.apache.kafka.common.serialization.StringSerializer");
        props.put("value.serializer",
            "org.apache.kafka.common.serialization.StringSerializer");

        // TODO 1: KafkaProducer 생성
        KafkaProducer<String, String> producer = new KafkaProducer<>(props);

        List<String[]> events = Arrays.asList(
            new String[]{"user1", "login"},
            new String[]{"user2", "login"},
            new String[]{"user3", "login"},
            new String[]{"user1", "view"},
            new String[]{"user2", "purchase"},
            new String[]{"user1", "purchase"},
            new String[]{"user3", "logout"},
            new String[]{"user2", "logout"},
            new String[]{"user1", "logout"}
        );

        // TODO 2: 전송 및 파티션 번호 출력
        Map<String, Integer> keyPartitionMap = new HashMap<>();

        for (String[] event : events) {
            String key = event[0];
            String value = event[1];
            ProducerRecord<String, String> record =
                new ProducerRecord<>("events", key, value);

            RecordMetadata meta = producer.send(record).get(); // 동기 전송
            System.out.printf("key=%-6s value=%-10s -> partition=%d offset=%d%n",
                key, value, meta.partition(), meta.offset());

            // TODO 3: 일관성 검증
            keyPartitionMap.merge(key, meta.partition(), (existing, incoming) -> {
                if (!existing.equals(incoming)) {
                    throw new RuntimeException(
                        "순서 보장 깨짐! key=" + key +
                        " 이전 partition=" + existing +
                        " 현재 partition=" + incoming);
                }
                return existing;
            });
        }

        System.out.println("\n=== 키별 파티션 배정 결과 ===");
        keyPartitionMap.forEach((key, partition) ->
            System.out.printf("key=%-6s -> partition=%d (모든 메시지 동일)%n", key, partition));

        // TODO 4: producer 닫기
        producer.close();
    }
}

/* 기대 출력 예시:
   key=user1  value=login      -> partition=1 offset=0
   key=user2  value=login      -> partition=3 offset=0
   key=user3  value=view       -> partition=2 offset=0
   key=user1  value=view       -> partition=1 offset=1   <- user1은 항상 partition=1
   key=user2  value=purchase   -> partition=3 offset=1
   ...
   === 키별 파티션 배정 결과 ===
   key=user1  -> partition=1 (모든 메시지 동일)
   key=user2  -> partition=3 (모든 메시지 동일)
   key=user3  -> partition=2 (모든 메시지 동일)
*/

