// PriorityPartitioner.java
import org.apache.kafka.clients.producer.Partitioner;
import org.apache.kafka.common.Cluster;
import java.util.Map;

public class PriorityPartitioner implements Partitioner {

    @Override
    public int partition(String topic, Object key, byte[] keyBytes,
                         Object value, byte[] valueBytes, Cluster cluster) {
        int numPartitions = cluster.partitionsForTopic(topic).size();

        // TODO 1: 방어 로직
        if (numPartitions < 3) {
            throw new IllegalStateException(
                "PriorityPartitioner 는 파티션 3개 이상 필요. 현재 수: " + numPartitions);
        }

        String keyStr = (key != null) ? key.toString() : "";

        // TODO 2: VIP 전용 파티션 0
        if (keyStr.startsWith("VIP:")) {
            return 0;
        }

        // TODO 3: BATCH 전용 파티션 (마지막)
        if (keyStr.startsWith("BATCH:")) {
            return numPartitions - 1;
        }

        // TODO 4: 일반 키 — 파티션 1 ~ numPartitions-2 에 해시 분산
        //   사용 가능한 파티션 수: numPartitions - 2 (양 끝 제외)
        int availablePartitions = numPartitions - 2;
        return 1 + Math.floorMod(keyStr.hashCode(), availablePartitions);
    }

    @Override public void configure(Map<String, ?> configs) {}
    @Override public void close() {}
}

