import org.apache.kafka.clients.producer.*;
import java.util.*;

public class PriorityPartitionerTest {
    public static void main(String[] args) throws Exception {
        Properties props = new Properties();
        props.put("bootstrap.servers", "localhost:9092");
        props.put("key.serializer",
            "org.apache.kafka.common.serialization.StringSerializer");
        props.put("value.serializer",
            "org.apache.kafka.common.serialization.StringSerializer");

        // TODO 5: 커스텀 파티셔너 등록
        props.put("partitioner.class", "PriorityPartitioner"); // 패키지명이 있으면 FQCN 사용

        KafkaProducer<String, String> producer = new KafkaProducer<>(props);

        List<String[]> testMessages = Arrays.asList(
            new String[]{"VIP:user1",   "order_placed"},
            new String[]{"VIP:user2",   "payment_done"},
            new String[]{"BATCH:job1",  "report_gen"},
            new String[]{"BATCH:job2",  "data_export"},
            new String[]{"normal:user3","click"},
            new String[]{"normal:user4","view"}
        );

        // TODO 6: 전송 및 검증
        // events 토픽은 파티션 4개: 0=VIP전용, 1~2=일반, 3=BATCH전용
        boolean allPassed = true;
        for (String[] msg : testMessages) {
            String key   = msg[0];
            String value = msg[1];
            RecordMetadata meta = producer.send(
                new ProducerRecord<>("events", key, value)).get();

            int  partition = meta.partition();
            int  total     = 4; // events 토픽 파티션 수
            boolean ok;
            if (key.startsWith("VIP:"))   ok = (partition == 0);
            else if (key.startsWith("BATCH:")) ok = (partition == total - 1);
            else                           ok = (partition >= 1 && partition <= total - 2);

            System.out.printf("%s %-12s -> partition=%d  [%s]%n",
                ok ? "PASS" : "FAIL", key, partition, ok ? "OK" : "EXPECTED 다름");
            if (!ok) allPassed = false;
        }

        System.out.println(allPassed ? "\n전체 검증 통과" : "\n검증 실패 — 파티셔너 로직 재확인 필요");
        producer.close();
    }
}

